    // 创建渐变层
    CAGradientLayer *gradientLayer = [CAGradientLayer layer];
    gradientLayer.frame = self.view.bounds;

    // 设置渐变颜色 - 从上到下
    UIColor *topColor = [UIColor colorWithRed:187/255.0 green:231/255.0 blue:250/255.0 alpha:1.0];
    UIColor *bottomColor = [UIColor colorWithRed:240/255.0 green:251/255.0 blue:255/255.0 alpha:1.0];

    gradientLayer.colors = @[
        (id)topColor.CGColor,
        (id)bottomColor.CGColor
    ];

    // 设置渐变方向 - 从上到下
    gradientLayer.startPoint = CGPointMake(0.5, 0.0); // 顶部中间
    gradientLayer.endPoint = CGPointMake(0.5, 1.0);   // 底部中间

    // 添加到视图最底层
    [self.view.layer insertSublayer:gradientLayer atIndex:0];

}

