- (void)toneSelected:(ToneView *)selectedTone {
    self.selectedEffect = selectedTone.type;

    for (ToneView *tone in self.tones) {
        BOOL able = [tone.type isEqualToString:self.selectedEffect];
        tone.selectedButton.hidden = YES;
        tone.layer.borderColor = able ? RGBA(54, 205, 106, 1).CGColor : UIColor.clearColor.CGColor;
        tone.layer.borderWidth = able ? 1.5 : 1.0;
        if (able) {
            self.selectedView = tone;
        }
        if (able && _hasRecord) {
            tone.playButton.enabled = YES;
        } else {
            tone.playButton.enabled = NO;
        }
    }

    // 如果录音已存在，切换时重新播放对应特效
    if (self.recordFileURL) {
        [self playWithEffect:self.selectedEffect];
    }
}

