        tone.layer.borderWidth = isSelected ? 1.5 : 1.0;
        [tone.playButton addTarget:self action:@selector(playRecordedAudio) forControlEvents:UIControlEventTouchUpInside];


        __weak typeof(self) weakSelf = self;
